prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDirection WHERE {
  ?gw a bboExt:ExclusiveGateway .
  ?gw tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDirection . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?pathEnd ?pathEndName WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8B059A72-97FC-4FC5-8321-9E7C9B523303> ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?pathEnd .
  ?pathEnd a bboExt:EndEvent .
  OPTIONAL { ?pathEnd bbo:name ?pathEndName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?endEvent ?endName WHERE {
  ?endEvent a bboExt:EndEvent .
  ?endEvent tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> .
  OPTIONAL { ?endEvent bbo:name ?endName . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> .
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Trace all paths from start event through the choreography
# List all distinct end points reachable and the paths to them
SELECT DISTINCT ?endNode ?endName ?pathLength WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8B059A72-97FC-4FC5-8321-9E7C9B523303> ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endNode .
  ?endNode a bboExt:EndEvent .
  OPTIONAL { ?endNode bbo:name ?endName . }
  # Calculate path length (number of hops)
  {
    SELECT ?endNode (COUNT(?intermediate) AS ?pathLength) WHERE {
      <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8B059A72-97FC-4FC5-8321-9E7C9B523303> ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?intermediate .
      ?intermediate ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endNode .
      ?endNode a bboExt:EndEvent .
    }
    GROUP BY ?endNode
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Check what type of elements these other "end" nodes are
SELECT ?elem ?type ?name WHERE {
  VALUES ?elem {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-89204608-1AF9-4FF0-B8C6-4922274D038D>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-68476F4A-93DB-457F-AEAB-580ABA4834F9>
  }
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}
